## CVXPY SOURCE: index.py lines 88-90

method(numeric_value, Index) <- function(x, values, ...) {
  val <- values[[1L]]
  if (!is.matrix(val)) val <- matrix(val, ncol = 1L)
  result <- val[x@key[[1L]], x@key[[2L]], drop = FALSE]
  result
}

